custom_css:
/* - - - - - - - - - - - - - - - - -

   "Black Orange"
   Pure black with orange highlights

   - - - - - - - - - - - - - - - - - */

:root {
    --customThemeColor-primary: rgba(255, 140, 0, 1);
    --customThemeColor-secondary: rgba(255, 165, 0, 1);
    --customTopBarColor: rgba(0, 0, 0, 0.95);
    --Drawer-iconColor: rgba(255, 140, 0, 0.9);
    --sheldBackgroundColor: rgba(0, 0, 0, 0);
    --custom-avatar: calc(var(--avatar-base-width) * 0.8);
    --customThemeMenuColor: var(--SmartThemeChatTintColor);
    --active: var(--customThemeColor-primary);
    --SmartThemeCheckboxTickColor: rgba(0, 0, 0, 1);
    --fullred: rgb(229, 57, 53);
    --crimson70a: rgb(229, 57, 53);
    --white30a: rgba(20, 20, 20, 0.9);
    --white50a: var(--customThemeColor-primary);
    --white70a: var(--customThemeColor-primary);
    --black30a: rgba(0, 0, 0, 0.3);
    --black50a: rgba(0, 0, 0, 0.5);
    --cobalt30a: rgba(0, 0, 0, 0.3);
    --okGreen70a: rgba(255, 140, 0, 0.8);
    --warning: var(--customThemeColor-primary);
    --golden: var(--customThemeColor-primary);
}

a { color: var(--customThemeColor-primary); }
a:hover { color: var(--customThemeColor-secondary); }
::selection { background-color: color-mix(in srgb, var(--customThemeColor-primary) 50%, transparent 50%); color: #FFF; }
h1, h2, h3 { color: var(--customThemeColor-primary); }
h3 { border-left: 5px solid var(--customThemeColor-primary); }
code { color: var(--customThemeColor-primary); }
.lastInContext { border-top: 3px dotted var(--customThemeColor-primary) !important; }
#chat .mes[is_user="true"] .name_text { color: var(--customThemeColor-primary) !important; }
#chat .mes[is_user="true"] .avatar { border: 1px solid var(--customThemeColor-primary) !important; }
.drawer-icon { color: var(--Drawer-iconColor) !important; text-shadow: 0 0 5px var(--customThemeColor-primary); }
#top-bar { background-color: var(--customTopBarColor) !important; }
#left-nav-panel, #right-nav-panel, .drawer-content { background-color: rgba(0, 0, 0, 0.95) !important; }
.drawer-content { border: 1px solid var(--customThemeColor-primary); }
#bg_custom { background-color: rgba(0, 0, 0, 1) !important; }
body { background-color: rgba(0, 0, 0, 1) !important; }
.mes_text { color: rgba(255, 255, 255, 1) !important; }
blockquote { border-left: 3px solid var(--customThemeColor-primary); color: var(--customThemeColor-primary); }
.menu_button { color: var(--customThemeColor-primary) !important; }
.menu_button:hover { background-color: rgba(255, 140, 0, 0.2) !important; }
input, textarea, select { background-color: rgba(10, 10, 10, 0.9) !important; color: rgba(255, 255, 255, 1) !important; border: 1px solid var(--customThemeColor-primary); }
input:focus, textarea:focus, select:focus { border-color: var(--customThemeColor-secondary); box-shadow: 0 0 5px var(--customThemeColor-primary); }
button { background-color: rgba(255, 140, 0, 0.2) !important; color: var(--customThemeColor-primary) !important; border: 1px solid var(--customThemeColor-primary); }
button:hover { background-color: rgba(255, 140, 0, 0.4) !important; }
.mes_block { background-color: rgba(0, 0, 0, 0.8) !important; }
.swipe_left, .swipe_right { color: var(--customThemeColor-primary) !important; }
.fa-solid, .fa-regular { color: var(--customThemeColor-primary); }
.inline-drawer-content { background-color: rgba(0, 0, 0, 0.95) !important; border: 1px solid var(--customThemeColor-primary); }
